import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import './Login.css';


function Login() {
  const [email, setEmail] = useState(""); 
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Freelancer"); 
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setIsLoading(true);

    try {
      const response = await fetch('http://localhost:3000/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password, role }),
      });

      const data = await response.json();

      if (response.ok) {
        localStorage.setItem('token', data.token);
        localStorage.setItem('userRole', role);
        alert("Login Successful!");
        navigate("/"); 
      } else {
        setError(data.msg || "Invalid Credentials");
      }
    } catch (error) {
      setError("Server शी संपर्क होत नाहीये. कृपया बॅकएंड चेक करा.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', background: '#f1f5f9' }}>
      <div style={{ background: 'white', padding: '40px', borderRadius: '15px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', width: '350px' }}>
        <h2 style={{ textAlign: 'center', color: '#1e293b' }}>{role} Login</h2>
        
        {error && <p style={{ color: 'red', textAlign: 'center', fontSize: '14px' }}>{error}</p>}
        
        <form onSubmit={handleLogin}>
          <div style={{ marginBottom: '15px' }}>
            <label>Select Role</label>
            <select value={role} onChange={(e) => setRole(e.target.value)} style={{ width: '100%', padding: '10px', marginTop: '5px', borderRadius: '8px', border: '1px solid #cbd5e1' }}>
              <option value="Freelancer">Freelancer</option>
              <option value="Client">Client (Hirer)</option>
            </select>
          </div>

          <input type="email" placeholder="Email Address" value={email} onChange={(e) => setEmail(e.target.value)} required 
            style={{ width: '100%', padding: '12px', marginBottom: '15px', borderRadius: '8px', border: '1px solid #cbd5e1', boxSizing: 'border-box' }} />
          
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required 
            style={{ width: '100%', padding: '12px', marginBottom: '20px', borderRadius: '8px', border: '1px solid #cbd5e1', boxSizing: 'border-box' }} />

          <button type="submit" disabled={isLoading} style={{ width: '100%', padding: '12px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>
            {isLoading ? "Logging in..." : "Login Now"}
          </button>
        </form>
        
        <p style={{ textAlign: 'center', marginTop: '15px', fontSize: '14px' }}>
          Don't have an account? <span style={{ color: '#38bdf8', cursor: 'pointer' }}>Signup</span>
        </p>
      </div>
    </div>
  );
}

export default Login;
